  ConstraintInfo(const DataLayout &DL, ArrayRef<Value *> FunctionArgs)
      : UnsignedCS(FunctionArgs), SignedCS(FunctionArgs), DL(DL) {
    auto &Value2Index = getValue2Index(false);
    // Add Arg > -1 constraints to unsigned system for all function arguments.
    for (Value *Arg : FunctionArgs) {
      ConstraintTy VarPos(SmallVector<int64_t, 8>(Value2Index.size() + 1, 0),
                          false, false, false);
      VarPos.Coefficients[Value2Index[Arg]] = -1;
      UnsignedCS.addVariableRow(VarPos.Coefficients);

      // Add constraints from range metadata if present.
      if (auto *RangeMD = Arg->getMetadata(LLVMContext::MD_range)) {
        ConstantRange Range = getConstantRangeFromMetadata(*RangeMD);
        if (!Range.isEmptySet()) {
          // Add Arg >= Range.lower() constraint.
          // Constraint format: c0 >= c1*v1, so Arg >= lower means:
          // -lower >= -Arg, i.e., coefficients[-lower, -1 for Arg]
          int64_t Lower = Range.getLower().getSExtValue();
          ConstraintTy LowerConstraint(
              SmallVector<int64_t, 8>(Value2Index.size() + 1, 0), false, false,
              false);
          LowerConstraint.Coefficients[0] = -Lower;
          LowerConstraint.Coefficients[Value2Index[Arg]] = 1;
          SignedCS.addVariableRow(LowerConstraint.Coefficients);

          // Add Arg < Range.upper() constraint, which is Arg <= upper - 1.
          // Constraint format: c0 >= c1*v1, so Arg <= upper-1 means:
          // (upper-1) >= Arg, i.e., coefficients[upper-1, 1 for Arg]
          int64_t Upper = Range.getUpper().getSExtValue();
          int64_t UpperMinus1;
          if (!SubOverflow(Upper, int64_t(1), UpperMinus1)) {
            ConstraintTy UpperConstraint(
                SmallVector<int64_t, 8>(Value2Index.size() + 1, 0), false,
                false, false);
            UpperConstraint.Coefficients[0] = UpperMinus1;
            UpperConstraint.Coefficients[Value2Index[Arg]] = -1;
            SignedCS.addVariableRow(UpperConstraint.Coefficients);
          }
        }
      }
    }
  }
